import{_ as n,a as i,b as t,c as a,d as r,e as d,f as s,g as l}from"./chunks/无关系记录重新申请.D_1qirb1.js";import{_ as o,o as h,c,a2 as u}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"Föderierter verteilter Index","description":"","frontmatter":{},"headers":[],"relativePath":"de-DE/Other/federated-distributed-index.md","filePath":"de-DE/Other/federated-distributed-index.md","lastUpdated":1781962217000}'),g={name:"de-DE/Other/federated-distributed-index.md"};function p(m,e,b,k,f,x){return h(),c("div",null,[...e[0]||(e[0]=[u('<h1 id="foderierter-verteilter-index" tabindex="-1">Föderierter verteilter Index <a class="header-anchor" href="#foderierter-verteilter-index" aria-label="Permalink to &quot;Föderierter verteilter Index&quot;">​</a></h1><p>Der föderierte verteilte Index ermöglicht es mehreren ImgBed-Seiten, Dateilisten miteinander zu teilen.</p><p>Kurz gesagt:</p><ul><li>Du kannst bestimmte Ordner deiner Seite mit anderen teilen.</li><li>Du kannst einem fremden Knoten beitreten und dessen freigegebene Dateiliste in deinen Adminbereich synchronisieren.</li><li>Föderierte Dateien dienen zum Durchsuchen, Anzeigen, Vorschauen und Kopieren von Links. Sie werden nicht in deinen eigenen Speicher erneut hochgeladen.</li></ul><h2 id="wo-einstellen" tabindex="-1">Wo einstellen <a class="header-anchor" href="#wo-einstellen" aria-label="Permalink to &quot;Wo einstellen&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Systemeinstellungen -&gt; Weitere Einstellungen -&gt; Föderierter verteilter Index</span></span></code></pre></div><p><img src="'+n+`" alt="Lokaler Knoten" loading="lazy"></p><p>Die Seite besteht aus drei Tabs:</p><table tabindex="0"><thead><tr><th>Tab</th><th>Zweck</th></tr></thead><tbody><tr><td>Lokaler Knoten</td><td>Eigenen Knoten, öffentliche Domain, freigegebene Ordner und ausgehenden Index verwalten</td></tr><tr><td>Beigetretene Knoten</td><td>Knoten anderer ImgBed-Seiten verwalten</td></tr><tr><td>Anfragen an meinen Knoten</td><td>Beitrittsanfragen anderer Personen verwalten</td></tr></tbody></table><h2 id="ersteinrichtung" tabindex="-1">Ersteinrichtung <a class="header-anchor" href="#ersteinrichtung" aria-label="Permalink to &quot;Ersteinrichtung&quot;">​</a></h2><ol><li>Öffne <code>Lokaler Knoten</code>.</li><li>Aktiviere <code>Aktivieren</code>.</li><li>Wähle unter <code>Synchronisierte Ordner</code> die Ordner aus, die du freigeben möchtest.</li><li>Klicke auf <code>Ausgehenden Index aktualisieren</code>.</li><li>Wenn ImgBed eine Domainänderung erkennt, bestätige, dass die aktuelle Domain die richtige Produktionsdomain ist.</li></ol><p>Du kannst mehrere Ordner auswählen. Bleibt die Liste leer, werden alle Ordner freigegeben.</p><h2 id="lokaler-knoten" tabindex="-1">Lokaler Knoten <a class="header-anchor" href="#lokaler-knoten" aria-label="Permalink to &quot;Lokaler Knoten&quot;">​</a></h2><h3 id="offentliche-domain" tabindex="-1">Öffentliche Domain <a class="header-anchor" href="#offentliche-domain" aria-label="Permalink to &quot;Öffentliche Domain&quot;">​</a></h3><p>Die öffentliche Domain ist die Adresse, über die andere Knoten deine Seite erreichen.</p><p>ImgBed erkennt sie automatisch. Normalerweise musst du nichts manuell eintragen. Beim ersten Aktualisieren oder nach Domainwechsel wird eine Bestätigung angezeigt.</p><h3 id="synchronisierte-ordner" tabindex="-1">Synchronisierte Ordner <a class="header-anchor" href="#synchronisierte-ordner" aria-label="Permalink to &quot;Synchronisierte Ordner&quot;">​</a></h3><p>Diese Ordner bestimmen, welche Dateien freigegeben werden.</p><p>Beispiel:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/</span></span>
<span class="line"><span>/2/</span></span></code></pre></div><p>Andere Knoten sehen dann nur Dateien in diesen beiden Verzeichnissen.</p><h3 id="ausgehenden-index-aktualisieren" tabindex="-1">Ausgehenden Index aktualisieren <a class="header-anchor" href="#ausgehenden-index-aktualisieren" aria-label="Permalink to &quot;Ausgehenden Index aktualisieren&quot;">​</a></h3><p>Aktualisiert die Dateiliste, die andere Knoten von deiner Seite synchronisieren können.</p><p>Nutze diese Aktion, wenn:</p><ul><li>du die Föderation erstmals aktivierst;</li><li>du neue Dateien freigeben möchtest;</li><li>du freigegebene Ordner änderst;</li><li>du die öffentliche Domain wechselst.</li></ul><h2 id="anderen-knoten-beitreten" tabindex="-1">Anderen Knoten beitreten <a class="header-anchor" href="#anderen-knoten-beitreten" aria-label="Permalink to &quot;Anderen Knoten beitreten&quot;">​</a></h2><p><code>Beigetretene Knoten</code> ist der Bereich für Knoten anderer ImgBed-Seiten.</p><p><img src="`+i+'" alt="Beigetretene Knoten" loading="lazy"></p><ol><li>Bitte den Betreiber des anderen Knotens um einen Einladungslink.</li><li>Füge ihn in das Eingabefeld ein.</li><li>Klicke auf <code>Beitritt beantragen</code>.</li><li>Warte, bis die andere Seite im Adminbereich zustimmt.</li></ol><p>Nach Zustimmung nutzt du <code>Eingehenden Index aktualisieren</code>, um die freigegebenen Dateien zu synchronisieren.</p><p>Für nur einen Knoten kannst du auf dessen Karte <code>Index aktualisieren</code> verwenden.</p><p><img src="'+t+'" alt="Index aktualisieren" loading="lazy"></p><h2 id="anfragen-an-deinen-knoten-verwalten" tabindex="-1">Anfragen an deinen Knoten verwalten <a class="header-anchor" href="#anfragen-an-deinen-knoten-verwalten" aria-label="Permalink to &quot;Anfragen an deinen Knoten verwalten&quot;">​</a></h2><p><code>Anfragen an meinen Knoten</code> zeigt Personen, die deinem Knoten beitreten möchten.</p><p><img src="'+a+'" alt="Anfragen an meinen Knoten" loading="lazy"></p><p>Für einen Einladungslink aktiviere den lokalen Knoten, führe mindestens einmal <code>Ausgehenden Index aktualisieren</code> aus, bestätige die öffentliche Domain und klicke dann auf <code>Einladungslink zurücksetzen</code>.</p><p>Bei einer Anfrage kannst du wählen:</p><table tabindex="0"><thead><tr><th>Aktion</th><th>Ergebnis</th></tr></thead><tbody><tr><td>Genehmigen</td><td>Die andere Seite darf deine freigegebene Liste synchronisieren</td></tr><tr><td>Ablehnen</td><td>Beitritt wird verweigert</td></tr><tr><td>Löschen</td><td>Abgeschlossenen Eintrag entfernen</td></tr><tr><td>Status prüfen</td><td>Prüfen, ob die andere Seite die Beziehung noch hält</td></tr></tbody></table><p>Nach Genehmigung muss die andere Seite den eingehenden Index aktualisieren, um deine Dateien zu sehen.</p><p><img src="'+r+'" alt="Knoten genehmigen" loading="lazy"></p><h2 id="nachrichten" tabindex="-1">Nachrichten <a class="header-anchor" href="#nachrichten" aria-label="Permalink to &quot;Nachrichten&quot;">​</a></h2><p>Nach Genehmigung kannst du auf der Knotenkarte <code>Nachricht</code> verwenden.</p><p>Nachrichten dienen nur der Abstimmung zur Föderation. Sie ändern keine Dateien, Tags, Ordner oder Rechte.</p><p><img src="'+d+'" alt="Nachrichten" loading="lazy"></p><h2 id="foderierte-dateien-anzeigen" tabindex="-1">Föderierte Dateien anzeigen <a class="header-anchor" href="#foderierte-dateien-anzeigen" aria-label="Permalink to &quot;Föderierte Dateien anzeigen&quot;">​</a></h2><p>Nach der Synchronisierung gehst du zurück zur Dateiliste im Adminbereich. Oben kannst du zwischen lokalen und föderierten Dateien wechseln.</p><p>Föderierte Dateien sind nicht lokal. Du kannst sie ansehen, durchsuchen, voranzeigen und Links kopieren, aber nicht verschieben, löschen, umtaggen oder sichern.</p><p><img src="'+s+'" alt="Anzeige im Adminbereich" loading="lazy"></p><h2 id="haufige-fragen" tabindex="-1">Häufige Fragen <a class="header-anchor" href="#haufige-fragen" aria-label="Permalink to &quot;Häufige Fragen&quot;">​</a></h2><h3 id="es-wird-angezeigt-dass-keine-beziehung-existiert" tabindex="-1">Es wird angezeigt, dass keine Beziehung existiert <a class="header-anchor" href="#es-wird-angezeigt-dass-keine-beziehung-existiert" aria-label="Permalink to &quot;Es wird angezeigt, dass keine Beziehung existiert&quot;">​</a></h3><p>Meist hat die andere Seite deinen Eintrag gelöscht. Stelle in diesem Fall eine neue Beitrittsanfrage.</p><p><img src="'+l+'" alt="Erneut beantragen" loading="lazy"></p><h3 id="ich-bin-beigetreten-sehe-aber-keine-dateien" tabindex="-1">Ich bin beigetreten, sehe aber keine Dateien <a class="header-anchor" href="#ich-bin-beigetreten-sehe-aber-keine-dateien" aria-label="Permalink to &quot;Ich bin beigetreten, sehe aber keine Dateien&quot;">​</a></h3><p>Prüfe:</p><ol><li>Die andere Seite hat deine Anfrage genehmigt.</li><li>Die andere Seite hat ihren ausgehenden Index aktualisiert.</li><li>Du hast deinen eingehenden Index aktualisiert.</li><li>Die synchronisierten Ordner der anderen Seite enthalten die freigegebenen Verzeichnisse.</li></ol>',55)])])}const v=o(g,[["render",p]]);export{_ as __pageData,v as default};
